import{_ as e,o as a,c as i,ao as r}from"./chunks/framework.B9--V88m.js";const p=JSON.parse('{"title":"Comparison with MATFrost.jl","description":"","frontmatter":{},"headers":[],"relativePath":"guide/comparison.md","filePath":"guide/comparison.md","lastUpdated":null}'),s={name:"guide/comparison.md"};function l(n,t,o,d,h,g){return a(),i("div",null,[...t[0]||(t[0]=[r(`<h1 id="Comparison-with-MATFrost.jl" tabindex="-1">Comparison with MATFrost.jl <a class="header-anchor" href="#Comparison-with-MATFrost.jl" aria-label="Permalink to &quot;Comparison with MATFrost.jl {#Comparison-with-MATFrost.jl}&quot;">​</a></h1><p><a href="https://github.com/ASML-Labs/MATFrost.jl" target="_blank" rel="noreferrer">MATFrost.jl</a> is the other Julia→MATLAB bridging library. The two projects share the same goal — call Julia from MATLAB — but make opposite architectural bets.</p><h2 id="Architecture" tabindex="-1">Architecture <a class="header-anchor" href="#Architecture" aria-label="Permalink to &quot;Architecture {#Architecture}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;"></th><th style="text-align:right;"><strong>Mexicah</strong></th><th style="text-align:right;"><strong>MATFrost</strong></th></tr></thead><tbody><tr><td style="text-align:right;">Delivery model</td><td style="text-align:right;">AOT-compiled MEX binary (<code>juliac --trim</code>)</td><td style="text-align:right;">Runtime server (<code>matfrost_spawn</code>)</td></tr><tr><td style="text-align:right;">Julia on end-user machine</td><td style="text-align:right;"><strong>Not required</strong></td><td style="text-align:right;">Required</td></tr><tr><td style="text-align:right;">IPC mechanism</td><td style="text-align:right;">None — MEX runs in-process</td><td style="text-align:right;">TCP socket (loopback)</td></tr><tr><td style="text-align:right;">Startup latency</td><td style="text-align:right;">MEX loads in milliseconds</td><td style="text-align:right;">Julia server starts once, stays alive</td></tr><tr><td style="text-align:right;">Per-call overhead</td><td style="text-align:right;">Minimal — just the MEX ccall</td><td style="text-align:right;">Serialization + TCP round-trip</td></tr></tbody></table><p>Mexicah compiles Julia functions into standalone <code>.mexa64</code>/<code>.mexw64</code> files that MATLAB loads like any other MEX. There is no Julia process, no sockets, and no runtime dependency on the target machine. The trade-off: <code>juliac --trim=safe</code> is stricter than full Julia — not all packages compile cleanly.</p><p>MATFrost keeps a persistent Julia process running alongside MATLAB and communicates over TCP. Compilation is trivial (any Julia code works), but the Julia runtime must be installed on every machine that runs the code.</p><h2 id="Type-support" tabindex="-1">Type support <a class="header-anchor" href="#Type-support" aria-label="Permalink to &quot;Type support {#Type-support}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Julia type</th><th style="text-align:right;">Mexicah</th><th style="text-align:right;">MATFrost</th></tr></thead><tbody><tr><td style="text-align:right;"><code>Float64</code> scalar</td><td style="text-align:right;">✓</td><td style="text-align:right;">✓</td></tr><tr><td style="text-align:right;"><code>Vector{Float64}</code></td><td style="text-align:right;">✓ zero-copy</td><td style="text-align:right;">✓</td></tr><tr><td style="text-align:right;"><code>Matrix{Float64}</code></td><td style="text-align:right;">✓ zero-copy</td><td style="text-align:right;">✓</td></tr><tr><td style="text-align:right;"><code>Int32</code> / <code>Int64</code></td><td style="text-align:right;">✓</td><td style="text-align:right;">✓</td></tr><tr><td style="text-align:right;"><code>Bool</code></td><td style="text-align:right;">✓</td><td style="text-align:right;">✓</td></tr><tr><td style="text-align:right;"><code>UInt64</code> (opaque handle)</td><td style="text-align:right;">✓ raw bits</td><td style="text-align:right;">✗</td></tr><tr><td style="text-align:right;"><code>SparseMatrixCSC{Float64}</code></td><td style="text-align:right;">✓</td><td style="text-align:right;">✓</td></tr><tr><td style="text-align:right;"><code>Vector{ComplexF64}</code></td><td style="text-align:right;">✓ zero-copy (R2018a+)</td><td style="text-align:right;">✓</td></tr><tr><td style="text-align:right;"><code>String</code></td><td style="text-align:right;">✓ <code>mxGetString</code> / <code>mxCreateString</code></td><td style="text-align:right;">✓</td></tr><tr><td style="text-align:right;">Nested structs</td><td style="text-align:right;">via handle registry</td><td style="text-align:right;">✓ native</td></tr><tr><td style="text-align:right;">Cell arrays</td><td style="text-align:right;">✗</td><td style="text-align:right;">✓</td></tr><tr><td style="text-align:right;"><code>DateTime</code></td><td style="text-align:right;">✗</td><td style="text-align:right;">✓</td></tr><tr><td style="text-align:right;"><code>DataFrame</code> / table</td><td style="text-align:right;">via handle registry</td><td style="text-align:right;">✗</td></tr></tbody></table><h2 id="Deployment-comparison" tabindex="-1">Deployment comparison <a class="header-anchor" href="#Deployment-comparison" aria-label="Permalink to &quot;Deployment comparison {#Deployment-comparison}&quot;">​</a></h2><p><strong>Mexicah</strong> — ship the <code>.mexa64</code> files:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my_project/</span></span>
<span class="line"><span>  solve_lp.mexa64        ← compiled MEX binary</span></span>
<span class="line"><span>  setup_paths.m          ← generated once by build_mex</span></span></code></pre></div><p>The recipient needs only MATLAB. No Julia installation, no network access, no server management. This is the right choice for distributing toolboxes.</p><p><strong>MATFrost</strong> — ship a Julia environment:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my_project/</span></span>
<span class="line"><span>  julia/                 ← full Julia environment</span></span>
<span class="line"><span>  src/MyFunctions.jl     ← source (not compiled)</span></span>
<span class="line"><span>  start_server.m         ← calls matfrost_spawn</span></span></code></pre></div><p>The recipient needs Julia installed and the correct package environment resolved. This is the right choice during development or when you need the full Julia type system.</p><h2 id="Choosing-between-them" tabindex="-1">Choosing between them <a class="header-anchor" href="#Choosing-between-them" aria-label="Permalink to &quot;Choosing between them {#Choosing-between-them}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Situation</th><th style="text-align:right;">Recommendation</th></tr></thead><tbody><tr><td style="text-align:right;">Distributing a toolbox to colleagues without Julia</td><td style="text-align:right;"><strong>Mexicah</strong></td></tr><tr><td style="text-align:right;">Using packages that don&#39;t compile with <code>juliac --trim</code></td><td style="text-align:right;"><strong>MATFrost</strong></td></tr><tr><td style="text-align:right;">Maximum array throughput (no IPC)</td><td style="text-align:right;"><strong>Mexicah</strong></td></tr><tr><td style="text-align:right;">Rich type vocabulary (cell arrays, DateTime, nested structs)</td><td style="text-align:right;"><strong>MATFrost</strong></td></tr><tr><td style="text-align:right;">Calling back from Julia into MATLAB</td><td style="text-align:right;"><strong>MATFrost</strong></td></tr><tr><td style="text-align:right;">Autonomous operation (no persistent process)</td><td style="text-align:right;"><strong>Mexicah</strong></td></tr></tbody></table><p>The projects are complementary. You can use Mexicah for performance-critical numerical kernels and MATFrost for exploratory work or where type richness matters.</p>`,18)])])}const y=e(s,[["render",l]]);export{p as __pageData,y as default};
